import React, { useEffect, useState, useCallback } from "react";
import { Link } from "react-router-dom";
import BookCard from "../components/BookCard";
import "./Home.css";

export default function Home() {
  const [books, setBooks]         = useState([]);
  const [loading, setLoading]     = useState(true);
  const [error, setError]         = useState("");
  const [featured, setFeatured]   = useState(0);
  const [carouselIdx, setCarouselIdx] = useState(0);

  const VISIBLE = 3;

  useEffect(() => {
    fetch("http://127.0.0.1:5000/api/popular")
      .then((r) => r.json())
      .then((data) => { setBooks(data); setLoading(false); })
      .catch(() => { setError("Could not load books. Is Flask running?"); setLoading(false); });
  }, []);

  /* Auto-cycle featured book every 5s */
  useEffect(() => {
    if (books.length === 0) return;
    const t = setInterval(() => {
      setFeatured((f) => {
        const next = (f + 1) % Math.min(books.length, 10);
        // keep carousel window showing the featured book
        setCarouselIdx((ci) => {
          if (next < ci) return next;
          if (next >= ci + VISIBLE) return next - VISIBLE + 1;
          return ci;
        });
        return next;
      });
    }, 5000);
    return () => clearInterval(t);
  }, [books]);

  const prevCarousel = useCallback(() => {
    setCarouselIdx((i) => Math.max(0, i - 1));
  }, []);

  const nextCarousel = useCallback(() => {
    setCarouselIdx((i) => Math.min(books.length - VISIBLE, i + 1));
  }, [books.length]);

  const selectFeatured = (idx) => {
    setFeatured(idx);
  };

  const feat = books[featured] || null;

  return (
    <div className="home">

      {/* ════════════════════════════════════════
           CINEMATIC HERO  (HBO-style)
      ════════════════════════════════════════ */}
      <section className="hero-cinema">

        {/* Blurred background from featured book cover */}
        <div className="hero-cinema__bg">
          {feat ? (
            <img
              key={feat.image}
              src={feat.image}
              alt=""
              className="hero-cinema__bg-img"
            />
          ) : (
            <div className="hero-cinema__bg-placeholder" />
          )}
          <div className="hero-cinema__overlay" />
        </div>

        <div className="hero-cinema__inner">

          {/* ── LEFT: Featured info ── */}
          <div className="hero-cinema__left">

            {/* Vertical progress dots */}
            <div className="hero-cinema__progress">
              {(books.length > 0 ? books.slice(0, 10) : Array(5).fill(null)).map((_, i) => (
                <button
                  key={i}
                  className={`hero-cinema__progress-dot ${i === featured ? "hero-cinema__progress-dot--active" : ""}`}
                  onClick={() => selectFeatured(i)}
                  aria-label={`Show book ${i + 1}`}
                />
              ))}
            </div>

            <div className="hero-cinema__info">
              {feat ? (
                <>
                  {/* Star rating */}
                  <div className="hero-cinema__stars">
                    {[1,2,3,4,5].map((s) => (
                      <span
                        key={s}
                        className={s <= Math.round(feat.rating ?? 0)
                          ? "hero-cinema__star hero-cinema__star--on"
                          : "hero-cinema__star"}
                      >★</span>
                    ))}
                    <span className="hero-cinema__rating-num">
                      {feat.rating?.toFixed(1)} / 5
                    </span>
                  </div>

                  {/* Title */}
                  <h1 className="hero-cinema__title">{feat.title}</h1>

                  {/* Description / author + votes */}
                  <p className="hero-cinema__desc">
                    by <em>{feat.author}</em> &nbsp;·&nbsp;{" "}
                    {feat.votes?.toLocaleString()} readers rated this book
                  </p>

                  {/* CTA buttons */}
                  <div className="hero-cinema__btns">
                    <Link to="/recommend" className="hero-cinema__btn-watch">
                      <span className="hero-cinema__play-icon">▶</span>
                      Get Recommendations
                    </Link>
                    <a href="#top50" className="hero-cinema__btn-info">
                      Browse All Books
                    </a>
                  </div>

                  {/* Season-style badge */}
                  <div className="hero-cinema__badge">
                    Rank #{featured + 1}
                  </div>
                </>
              ) : (
                /* Skeleton while loading */
                <div className="hero-cinema__info-skeleton">
                  <div className="skeleton" style={{width:130,height:18,borderRadius:6,marginBottom:20}}/>
                  <div className="skeleton" style={{width:"70%",height:52,borderRadius:8,marginBottom:14}}/>
                  <div className="skeleton" style={{width:"50%",height:16,borderRadius:6,marginBottom:32}}/>
                  <div style={{display:"flex",gap:12}}>
                    <div className="skeleton" style={{width:170,height:44,borderRadius:8}}/>
                    <div className="skeleton" style={{width:140,height:44,borderRadius:8}}/>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* ── RIGHT: Carousel ── */}
          <div className="hero-cinema__right">

            {/* Nav header */}
            <div className="hero-cinema__carousel-head">
              <div className="hero-cinema__carousel-nav">
                <button
                  className="hero-cinema__nav-btn"
                  onClick={prevCarousel}
                  disabled={carouselIdx === 0}
                  aria-label="Previous"
                >‹</button>
                <span className="hero-cinema__nav-count">
                  {String(carouselIdx + 1).padStart(2, "0")}
                  <span className="hero-cinema__nav-line" />
                  {String(Math.min(books.length, 50)).padStart(2, "0")}
                </span>
                <button
                  className="hero-cinema__nav-btn"
                  onClick={nextCarousel}
                  disabled={carouselIdx >= books.length - VISIBLE}
                  aria-label="Next"
                >›</button>
              </div>
            </div>

            {/* Cards */}
            <div className="hero-cinema__cards">
              {loading
                ? Array(VISIBLE).fill(0).map((_, i) => (
                    <div key={i} className="hero-cinema__card hero-cinema__card--skel">
                      <div className="skeleton" style={{width:"100%",height:"100%",borderRadius:12}}/>
                    </div>
                  ))
                : books.slice(carouselIdx, carouselIdx + VISIBLE).map((b, i) => {
                    const gIdx = carouselIdx + i;
                    return (
                      <div
                        key={b.title}
                        className={`hero-cinema__card ${gIdx === featured ? "hero-cinema__card--active" : ""}`}
                        onClick={() => selectFeatured(gIdx)}
                      >
                        {/* Bookmark icon */}
                        <span className="hero-cinema__bookmark">🔖</span>

                        <img src={b.image} alt={b.title} />

                        <div className="hero-cinema__card-info">
                          <span className="hero-cinema__card-ep">
                            #{gIdx + 1}
                          </span>
                          <p className="hero-cinema__card-title">{b.title}</p>
                          <span className="hero-cinema__card-rating">
                            ★ {b.rating?.toFixed(1)}
                          </span>
                        </div>
                      </div>
                    );
                  })
              }
            </div>

          </div>
        </div>
      </section>

      {/* ════════════════════════════════════════
           TOP 50 BOOKS  (unchanged)
      ════════════════════════════════════════ */}
      <section className="top50-section" id="top50">
        <div className="container">

          <div className="top50-header">
            <div>
              <h2 className="top50-title">Top 50 Books</h2>
              <p className="top50-sub">Ranked by community ratings &amp; popularity</p>
            </div>
            <Link to="/recommend" className="top50-cta">Find Similar Books →</Link>
          </div>

          {error && <div className="top50-error">⚠️ {error}</div>}

          {loading ? (
            <div className="books-grid">
              {Array(12).fill(0).map((_, i) => (
                <div key={i} className="book-skeleton">
                  <div className="skeleton" style={{height:280,borderRadius:12,marginBottom:12}}/>
                  <div className="skeleton" style={{height:14,borderRadius:6,marginBottom:8}}/>
                  <div className="skeleton" style={{height:12,width:"65%",borderRadius:6}}/>
                </div>
              ))}
            </div>
          ) : (
            <div className="books-grid">
              {books.map((b, i) => (
                <BookCard
                  key={i}
                  title={b.title}
                  author={b.author}
                  image={b.image}
                  rating={b.rating}
                  votes={b.votes}
                  rank={i + 1}
                  delay={Math.min(i * 35, 700)}
                />
              ))}
            </div>
          )}

        </div>
      </section>

      {/* ════════════════════════════════════════
           HOW IT WORKS  (unchanged)
      ════════════════════════════════════════ */}
      <section className="how-section" id="how-it-works">
        <div className="container">
          <h2 className="how-title">How It Works</h2>
          <p className="how-sub">Three steps to your next favourite book</p>
          <div className="how-steps">
            {[
              { icon:"🔍", step:"01", title:"Search a Book",  desc:"Enter any book title you already enjoy into our search bar." },
              { icon:"🤖", step:"02", title:"AI Analyses",    desc:"Our model finds readers with similar tastes and surfaces their favourites." },
              { icon:"📚", step:"03", title:"Discover Reads", desc:"Get 4 personalised recommendations with match scores." },
            ].map((s) => (
              <div key={s.step} className="how-card">
                <div className="how-card__icon">{s.icon}</div>
                <div className="how-card__step">{s.step}</div>
                <h3>{s.title}</h3>
                <p>{s.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

    </div>
  );
}
